import React, { useEffect, useRef, useMemo, type JSX } from "react";
import {
  createChart,
  LineSeries,
  type IChartApi,
  type ISeriesApi,
  type LineData,
  type UTCTimestamp,
} from "lightweight-charts";
import { TERMINAL_COLORS } from "../../constants/terminalColors";
import "./finchart.css";

export type IndicatorSeriesConfig = {
  id: string;
  label: string;
  data: LineData<UTCTimestamp>[];
  color: string;
  priceScaleId?: string;
  lineStyle?: 0 | 1 | 2 | 3 | 4;
};

export interface IndicatorLineChartProps {
  title: string;
  series: IndicatorSeriesConfig[];
  leftAxisLabel?: string;
  rightAxisLabel?: string;
  height?: number;
  legend?: Array<{ label: string; color: string; dashed?: boolean }>;
}

function IndicatorLineChart({
  title,
  series,
  leftAxisLabel,
  rightAxisLabel,
  height = 220,
  legend,
}: IndicatorLineChartProps): JSX.Element {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRefs = useRef<Map<string, ISeriesApi<"Line">>>(new Map());

  const seriesKey = useMemo(
    () =>
      series
        .map(
          (s) =>
            `${s.id}:${s.color}:${s.priceScaleId ?? "left"}:${s.lineStyle ?? 0}`,
        )
        .join("|"),
    [series],
  );

  useEffect(() => {
    if (!chartContainerRef.current) return;

    if (chartRef.current) {
      try {
        chartRef.current.remove();
      } catch {
        // ignore
      }
      chartRef.current = null;
      seriesRefs.current.clear();
    }

    let chart: IChartApi | null = null;
    let animationFrameId: number | null = null;
    let initAttempts = 0;
    const maxInitAttempts = 120;

    const initializeChart = () => {
      if (!chartContainerRef.current) return;

      const container = chartContainerRef.current;
      const containerWidth = container.clientWidth || container.offsetWidth;
      const containerHeight = container.clientHeight || container.offsetHeight;

      if (
        (!containerWidth ||
          containerWidth < 50 ||
          !containerHeight ||
          containerHeight < 60) &&
        initAttempts < maxInitAttempts
      ) {
        initAttempts += 1;
        animationFrameId = requestAnimationFrame(initializeChart);
        return;
      }

      try {
        const hasRightAxis = series.some((s) => s.priceScaleId === "right");

        chart = createChart(container, {
          autoSize: true,
          layout: {
            background: { color: TERMINAL_COLORS.bgDeep },
            textColor: TERMINAL_COLORS.textSecondary,
          },
          grid: {
            vertLines: { color: TERMINAL_COLORS.gridMajor },
            horzLines: { color: TERMINAL_COLORS.gridMajor },
          },
          crosshair: { mode: 1 },
          rightPriceScale: {
            borderColor: TERMINAL_COLORS.panelStrong,
            visible: Boolean(rightAxisLabel),
          },
          leftPriceScale: {
            borderColor: TERMINAL_COLORS.panelStrong,
            visible: true,
          },
          timeScale: {
            visible: true,
            borderVisible: true,
            borderColor: TERMINAL_COLORS.panelStrong,
            timeVisible: true,
            secondsVisible: false,
            ticksVisible: true,
            minimumHeight: 24,
          },
        });

        const refs = new Map<string, ISeriesApi<"Line">>();

        for (const config of series) {
          const scaleId = config.priceScaleId ?? "left";
          const lineSeries = chart.addSeries(LineSeries, {
            color: config.color,
            lineWidth: 2,
            priceScaleId: scaleId,
            lineStyle: config.lineStyle ?? 0,
            title: config.label,
          });

          if (config.data.length > 0) {
            lineSeries.setData(config.data);
          }

          refs.set(config.id, lineSeries);
        }

        if (hasRightAxis) {
          chart.priceScale("right").applyOptions({
            scaleMargins: { top: 0.1, bottom: 0.1 },
          });
        }

        chart.priceScale("left").applyOptions({
          scaleMargins: { top: 0.1, bottom: 0.1 },
        });

        chart.timeScale().fitContent();
        chartRef.current = chart;
        seriesRefs.current = refs;
      } catch (error) {
        console.error("[IndicatorLineChart] Error creating chart:", error);
      }
    };

    initializeChart();

    return () => {
      if (animationFrameId !== null) {
        cancelAnimationFrame(animationFrameId);
      }
      if (chart) {
        try {
          chart.remove();
        } catch {
          // ignore
        }
      }
      chartRef.current = null;
      seriesRefs.current.clear();
    };
  }, [height, leftAxisLabel, rightAxisLabel, seriesKey]);

  useEffect(() => {
    if (seriesRefs.current.size === 0) return;

    for (const config of series) {
      const lineSeries = seriesRefs.current.get(config.id);
      if (!lineSeries || config.data.length === 0) continue;
      try {
        lineSeries.setData(config.data);
      } catch (error) {
        console.error(
          "[IndicatorLineChart] Error updating series:",
          config.id,
          error,
        );
      }
    }

    chartRef.current?.timeScale().fitContent();
  }, [series]);

  return (
    <div className="indicator-line-chart-container" style={{ minHeight: height }}>
      <div className="indicator-line-chart-header">
        <span className="terminal-panel-title">{title}</span>
        {legend && legend.length > 0 ? (
          <div className="indicator-line-chart-legend">
            {legend.map((item) => (
              <span
                key={item.label}
                className={`indicator-line-chart-legend-item terminal-label${item.dashed ? " indicator-line-chart-legend-item--dashed" : ""}`}
              >
                <span
                  className="indicator-line-chart-legend-swatch"
                  style={{ backgroundColor: item.color }}
                />
                {item.label}
              </span>
            ))}
          </div>
        ) : null}
      </div>
      {(leftAxisLabel || rightAxisLabel) && (
        <div className="indicator-line-chart-axis-labels terminal-label">
          {leftAxisLabel ? (
            <span className="indicator-line-chart-axis-label indicator-line-chart-axis-label--left">
              {leftAxisLabel}
            </span>
          ) : null}
          {rightAxisLabel ? (
            <span className="indicator-line-chart-axis-label indicator-line-chart-axis-label--right">
              {rightAxisLabel}
            </span>
          ) : null}
        </div>
      )}
      <div ref={chartContainerRef} className="indicator-line-chart-canvas" />
    </div>
  );
}

export default IndicatorLineChart;
